/// 锁策略，用于在加锁前后执行特殊操作
pub trait MutexStrategy: 'static {
    type GuardData;
    fn new_guard() -> Self::GuardData;
}

pub struct DefaultStrategy;
pub struct IrqStrategy;

pub type Mutex<T> = spin::SpinMutex<T, DefaultStrategy>;
pub type IrqMutex<T> = spin::SpinMutex<T, IrqStrategy>;
pub type ReMutex<T> = reentrant::ReMutex<T, DefaultStrategy>;
pub type IrqReMutex<T> = reentrant::ReMutex<T, IrqStrategy>;
pub type AsyncMutex<T> = sync::AsyncMutex<T, DefaultStrategy>;

impl MutexStrategy for DefaultStrategy {
    type GuardData = ();

    fn new_guard() -> Self::GuardData {}
}

impl MutexStrategy for IrqStrategy {
    type GuardData = KIntrGuard;
    fn new_guard() -> Self::GuardData {
        KIntrGuard::new()
    }
}

use alloc::sync::Arc;
use core::arch::asm;
use aligned::{A16, Aligned};
use riscv::asm::fence_i;
use riscv::register::{satp, sstatus};
use riscv::register::sstatus::FS;
use crate::arch;
use crate::config::{KERNEL_STACK_SIZE, MAX_HARTS};
use crate::mm::asid::ASIDManager;
use crate::mm::KERNEL_SPACE;
use crate::mm::page_table::PageTable;
use crate::process::thread::Thread;
use crate::processor::context::HartContext;
use crate::result::SyscallResult;

pub struct Hart {
    pub id: usize,
    pub ctx: HartContext,
    pub on_kintr: bool,
    pub on_page_test: bool,
    pub last_page_fault: SyscallResult,
    kintr_rec: usize,
    asid_manager: Option<ASIDManager>,
}

pub struct KIntrGuard;

impl KIntrGuard {
    pub fn new() -> Self {
        local_hart().disable_kintr();
        Self
    }
}

impl Drop for KIntrGuard {
    fn drop(&mut self) {
        local_hart().enable_kintr();
    }
}

impl Hart {
    const fn new() -> Self {
        Self {
            id: 0,
            ctx: HartContext::kernel(),
            on_kintr: false,
            on_page_test: false,
            last_page_fault: Ok(()),
            kintr_rec: 0,
            asid_manager: None,
        }
    }

    pub fn current_thread(&self) -> Option<&Arc<Thread>> {
        self.ctx.user_task.as_ref().map(|t| &t.thread)
    }

    pub fn switch_ctx(&mut self, another: &mut HartContext) {
        self.disable_kintr();
        let (thread_now, task_next) = (
            self.current_thread(),
            another.user_task.as_mut(),
        );
        if let Some(now) = thread_now {
            now.inner().trap_ctx.fctx.sched_out();
            now.inner().rusage.sched_out();
        }
        if let Some(next) = task_next {
            next.thread.inner().rusage.sched_in();
            let switch_pt = match thread_now {
                Some(now) => now.tid != next.thread.tid,
                None => true,
            };
            if switch_pt {
                unsafe {
                    self.switch_page_table(next.token, next.root_pt);
                }
            }
        } else {
            if thread_now.is_some() {
                let kernel_space = KERNEL_SPACE.lock();
                unsafe {
                    self.switch_page_table(kernel_space.token, kernel_space.root_pt);
                }
            }
        }
        core::mem::swap(&mut self.ctx, another);
        self.enable_kintr();
    }

    pub fn enable_kintr(&mut self) {
        self.kintr_rec -= 1;
        if self.kintr_rec == 0 && !self.on_kintr {
            arch::enable_kernel_interrupt();
        }
    }

    pub fn disable_kintr(&mut self) {
        if self.kintr_rec == 0 {
            arch::disable_kernel_interrupt();
        }
        self.kintr_rec += 1;
    }

    pub unsafe fn switch_page_table(&mut self, token: usize, root_pt: PageTable) {
        self.disable_kintr();
        if let Some(manager) = &mut self.asid_manager {
            if let Some(asid) = manager.get(token) {
                fence_i();
                satp::set(satp::Mode::Sv39, asid as usize, root_pt.ppn.0);
                fence_i();
            } else {
                let asid = manager.assign(token);
                fence_i();
                satp::set(satp::Mode::Sv39, asid as usize, root_pt.ppn.0);
                asm!("sfence.vma x0, {}", in(reg) asid);
            }
        } else {
            satp::set(satp::Mode::Sv39, 0, root_pt.ppn.0);
            asm!("sfence.vma");
        }
        self.enable_kintr();
    }

    pub unsafe fn refresh_tlb(&mut self, token: usize) {
        self.disable_kintr();
        if let Some(manager) = &mut self.asid_manager {
            let asid = manager.get(token).unwrap();
            asm!("sfence.vma x0, {}", in(reg) asid);
        } else {
            asm!("sfence.vma");
        }
        self.enable_kintr();
    }
}

static mut HARTS: [Hart; MAX_HARTS] = [const { Hart::new() }; MAX_HARTS];

#[link_section = ".bss.uninit"]
pub static mut KERNEL_STACK: Aligned<A16, [u8; KERNEL_STACK_SIZE * MAX_HARTS]> = Aligned([0; KERNEL_STACK_SIZE * MAX_HARTS]);

pub fn local_hart() -> &'static mut Hart {
    unsafe {
        let tp: usize;
        asm!("mv {}, tp", out(reg) tp);
        &mut HARTS[tp]
    }
}

pub fn init(hart_id: usize) {
    unsafe {
        // 将当前 hart 的 id 保存到 tp 寄存器
        asm!("mv tp, {}", in(reg) hart_id);
        HARTS[hart_id].id = hart_id;
        HARTS[hart_id].asid_manager = ASIDManager::new();
        // 允许内核访问用户态地址空间
        sstatus::set_sum();
        sstatus::set_fs(FS::Clean);
    };
}

