use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use core::cmp::min;
use crate::arch::{PAGE_SIZE, PhysPageNum};
use crate::fs::inode::{DummyInode, Inode};
use crate::mm::allocator::{alloc_user_frames, UserFrameTracker};
use crate::result::SyscallResult;
use crate::sched::schedule;
use crate::sync::mutex::ReMutex;

pub struct PageCache(ReMutex<PageCacheInner>);

struct PageCacheInner {
    inode: Weak<dyn Inode>,
    file_size: usize,
    deleted: bool,
    pages: BTreeMap<usize, Page>,
}

struct Page {
    frame: UserFrameTracker,
    dirty: bool,
}

impl Page {
    fn new(frame: UserFrameTracker) -> Self {
        Self { frame, dirty: false }
    }
}

impl PageCache {
    pub fn new() -> Arc<Self> {
        Arc::new(Self(ReMutex::new(PageCacheInner {
            inode: Weak::<DummyInode>::new(),
            file_size: 0,
            deleted: false,
            pages: BTreeMap::new(),
        })))
    }

    pub fn ppn_of(&self, page_num: usize) -> Option<PhysPageNum> {
        self.0.lock().pages.get(&page_num).map(|page| page.frame.ppn)
    }

    pub fn set_inode(&self, inode: Arc<dyn Inode>) {
        let mut inner = self.0.lock();
        inner.inode = Arc::downgrade(&inode);
        inner.file_size = inode.metadata().inner.lock().size as usize;
    }

    pub fn set_deleted(&self) {
        self.0.lock().deleted = true;
    }

    pub async fn load(&self, page_num: usize) -> SyscallResult {
        let mut inner = self.0.lock();
        if inner.pages.get(&page_num).is_none() {
            let frame = alloc_user_frames(1)?;
            let page_buf = frame.ppn.byte_array();
            if !inner.deleted && let Some(inode) = inner.inode.upgrade() {
                inode.read_direct(page_buf, (page_num * PAGE_SIZE) as isize).await?;
            }
            inner.pages.insert(page_num, Page::new(frame));
        }
        Ok(())
    }

    pub async fn read(&self, mut buf: &mut [u8], offset: isize) -> SyscallResult<isize> {
        let mut offset = offset as usize;
        let file_size = self.0.lock().file_size;
        if offset >= file_size {
            return Ok(0);
        }
        if offset + buf.len() > file_size {
            buf = &mut buf[..file_size - offset];
        }
        let page_start = offset / PAGE_SIZE;
        let page_end = (offset + buf.len()).div_ceil(PAGE_SIZE);

        let mut cur = 0;
        offset = offset % PAGE_SIZE;
        for page_num in page_start..page_end {
            schedule().await;
            let mut inner = self.0.lock();
            let page = match inner.pages.get(&page_num) {
                Some(frame) => frame,
                None => {
                    let frame = alloc_user_frames(1)?;
                    let page_buf = frame.ppn.byte_array();
                    if !inner.deleted && let Some(inode) = inner.inode.upgrade() {
                        inode.read_direct(page_buf, (page_num * PAGE_SIZE) as isize).await?;
                    }
                    inner.pages.entry(page_num).or_insert(Page::new(frame))
                }
            };
            let page_buf = page.frame.ppn.byte_array();
            drop(inner);
            let len = min(buf.len() - cur, PAGE_SIZE - offset);
            buf[cur..cur + len].copy_from_slice(&page_buf[offset..offset + len]);
            cur += len;
            offset = 0;
        }
        Ok(cur as isize)
    }

    pub async fn write(&self, buf: &[u8], offset: isize) -> SyscallResult<isize> {
        let mut offset = offset as usize;
        let file_size = self.0.lock().file_size;
        if offset + buf.len() > file_size {
            self.truncate((offset + buf.len()) as isize).await?;
        }
        let page_start = offset / PAGE_SIZE;
        let page_end = (offset + buf.len()).div_ceil(PAGE_SIZE);

        let mut cur = 0;
        offset %= PAGE_SIZE;
        for page_num in page_start..page_end {
            schedule().await;
            let mut inner = self.0.lock();
            let page = match inner.pages.get_mut(&page_num) {
                Some(page) => page,
                None => {
                    let frame = alloc_user_frames(1)?;
                    inner.pages.entry(page_num).or_insert(Page::new(frame))
                }
            };
            let page_buf = page.frame.ppn.byte_array();
            page.dirty = true;
            drop(inner);
            let len = min(buf.len() - cur, PAGE_SIZE - offset);
            page_buf[offset..offset + len].copy_from_slice(&buf[cur..cur + len]);
            cur += len;
            offset = 0;
        }
        Ok(cur as isize)
    }

    pub async fn truncate(&self, size: isize) -> SyscallResult {
        let mut inner = self.0.lock();
        inner.file_size = size as usize;
        if inner.deleted {
            if let Some(inode) = inner.inode.upgrade() {
                inode.metadata().inner.lock().size = size;
            }
        } else {
            if let Some(inode) = inner.inode.upgrade() {
                inode.truncate_direct(size).await?;
            }
        }

        let page_num = size as usize / PAGE_SIZE;
        inner.pages.retain(|&k, _| k <= page_num);
        if let Some(page) = inner.pages.get_mut(&page_num) {
            let page_buf = page.frame.ppn.byte_array();
            page_buf[size as usize % PAGE_SIZE..].fill(0);
            page.dirty = true;
        }
        Ok(())
    }

    pub async fn sync(&self, offset: usize, len: usize) -> SyscallResult {
        let mut inner = self.0.lock();
        let inode = match inner.inode.upgrade() {
            Some(inode) => inode,
            None => return Ok(()),
        };
        if inner.deleted {
            return Ok(());
        }

        let file_size = inode.metadata().inner.lock().size as usize;
        let page_start = offset / PAGE_SIZE;
        let page_end = min(file_size, offset + len).div_ceil(PAGE_SIZE);
        for (page_num, page) in inner.pages.range_mut(page_start..page_end) {
            if page.dirty {
                let mut page_buf = page.frame.ppn.byte_array();
                if *page_num == file_size / PAGE_SIZE {
                    page_buf = &mut page_buf[..file_size % PAGE_SIZE];
                }
                inode.write_direct(page_buf, (page_num * PAGE_SIZE) as isize).await?;
                page.dirty = false;
            }
        }
        Ok(())
    }

    pub async fn sync_all(&self) -> SyscallResult {
        self.sync(0, usize::MAX).await
    }
}

impl Drop for PageCacheInner {
    fn drop(&mut self) {
        if self.inode.strong_count() != 0 {
            for page in self.pages.values() {
                if page.dirty {
                    panic!("Dirty page dropped");
                }
            }
        }
    }
}

use alloc::boxed::Box;
use alloc::collections::VecDeque;
use alloc::sync::{Arc, Weak};
use core::cmp::min;
use core::future::Future;
use core::pin::Pin;
use core::task::{Context, Poll, Waker};
use async_trait::async_trait;
use log::debug;
use crate::config::PIPE_BUF_CAP;
use crate::fs::ffi::OpenFlags;
use crate::fs::file::{File, FileMeta};
use crate::result::{Errno, SyscallResult};
use crate::sync::mutex::Mutex;
use crate::sync::once::LateInit;

pub struct Pipe {
    metadata: FileMeta,
    is_reader: bool,
    other: LateInit<Weak<Pipe>>,
    inner: Arc<Mutex<PipeInner>>,
}

#[derive(Default)]
struct PipeInner {
    buf: VecDeque<u8>,
    transfer: usize,
    readers: VecDeque<Waker>,
    writers: VecDeque<Waker>,
}

impl Drop for Pipe {
    fn drop(&mut self) {
        let mut inner = self.inner.lock();
        if self.is_reader {
            while let Some(waker) = inner.writers.pop_front() {
                waker.wake();
            }
        } else {
            while let Some(waker) = inner.readers.pop_front() {
                waker.wake();
            }
        }
    }
}

impl Pipe {
    pub fn new() -> (Arc<Self>, Arc<Self>) {
        let inner = Arc::new(Mutex::new(PipeInner::default()));
        let reader = Arc::new(Pipe {
            metadata: FileMeta::new(None, OpenFlags::O_RDONLY),
            is_reader: true,
            other: LateInit::new(),
            inner: inner.clone(),
        });
        let writer = Arc::new(Pipe {
            metadata: FileMeta::new(None, OpenFlags::O_WRONLY),
            is_reader: false,
            other: LateInit::new(),
            inner,
        });
        reader.other.init(Arc::downgrade(&writer));
        writer.other.init(Arc::downgrade(&reader));
        (reader, writer)
    }
}

#[async_trait]
impl File for Pipe {
    fn metadata(&self) -> &FileMeta {
        &self.metadata
    }

    async fn read(&self, buf: &mut [u8]) -> SyscallResult<isize> {
        if !self.is_reader {
            return Err(Errno::EBADF);
        }
        if buf.len() == 0 {
            return Ok(0);
        }
        PipeReadFuture {
            pipe: self,
            buf,
            pos: 0,
        }.await
    }

    async fn write(&self, buf: &[u8]) -> SyscallResult<isize> {
        if self.is_reader {
            return Err(Errno::EBADF);
        }
        if buf.len() == 0 {
            return Ok(0);
        }
        PipeWriteFuture {
            pipe: self,
            buf,
            pos: 0,
        }.await
    }

    fn pollin(&self, waker: Option<Waker>) -> SyscallResult<bool> {
        let mut inner = self.inner.lock();
        if !inner.buf.is_empty() || self.other.strong_count() == 0 {
            Ok(true)
        } else {
            if let Some(waker) = waker {
                inner.readers.push_back(waker);
            }
            Ok(false)
        }
    }

    fn pollout(&self, waker: Option<Waker>) -> SyscallResult<bool> {
        let mut inner = self.inner.lock();
        if self.other.strong_count() == 0 {
            Err(Errno::EPIPE)
        } else if inner.buf.len() < PIPE_BUF_CAP {
            Ok(true)
        } else {
            if let Some(waker) = waker {
                inner.writers.push_back(waker);
            }
            Ok(false)
        }
    }
}

struct PipeReadFuture<'a> {
    pipe: &'a Pipe,
    buf: &'a mut [u8],
    pos: usize,
}

struct PipeWriteFuture<'a> {
    pipe: &'a Pipe,
    buf: &'a [u8],
    pos: usize,
}

impl Future for PipeReadFuture<'_> {
    type Output = SyscallResult<isize>;

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let mut inner = self.pipe.inner.lock();
        let read = min(self.buf.len() - self.pos, inner.buf.len());
        debug!(
            "[pipe] read poll pos: {}, len: {}, buf.len: {}, read: {}",
            self.pos, self.buf.len(), inner.buf.len(), read,
        );
        if read > 0 {
            for (i, b) in inner.buf.drain(..read).enumerate() {
                self.buf[i] = b;
            }
            self.pos += read;
            inner.transfer += read;
            while let Some(waker) = inner.writers.pop_front() {
                waker.wake();
            }
            Poll::Ready(Ok(read as isize))
        } else {
            if self.pipe.other.strong_count() == 0 {
                return Poll::Ready(Ok(0));
            }
            inner.readers.push_back(cx.waker().clone());
            Poll::Pending
        }
    }
}

impl Future for PipeWriteFuture<'_> {
    type Output = SyscallResult<isize>;

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let mut inner = self.pipe.inner.lock();
        debug!(
            "[pipe] write poll len: {}, buf.len: {}",
            self.buf.len(), inner.buf.len(),
        );
        if self.pipe.other.strong_count() == 0 {
            return Poll::Ready(Err(Errno::EPIPE));
        }
        let write = min(self.buf.len() - self.pos, PIPE_BUF_CAP - inner.buf.len());
        if write > 0 {
            inner.buf.extend(&self.buf[self.pos..self.pos + write]);
            self.pos += write;
            while let Some(waker) = inner.readers.pop_front() {
                waker.wake();
            }
            Poll::Ready(Ok(write as isize))
        } else {
            inner.writers.push_back(cx.waker().clone());
            Poll::Pending
        }
    }
}

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use alloc::vec;
use alloc::vec::Vec;
use crate::mm::allocator::{alloc_user_frames, IdAllocator, UserFrameTracker};
use crate::result::SyscallResult;

#[derive(Default)]
pub struct SysVShm {
    ids: IdAllocator,
    shm: BTreeMap<usize, Vec<Arc<UserFrameTracker>>>,
}

impl SysVShm {
    pub fn alloc(&mut self, pages: usize) -> SyscallResult<usize> {
        let id = self.ids.alloc();
        let mut shm = vec![];
        for _ in 0..pages {
            let frame = alloc_user_frames(1)?;
            shm.push(Arc::new(frame));
        }
        self.shm.insert(id, shm);
        Ok(id)
    }

    pub fn get(&self, id: usize) -> Option<Vec<Arc<UserFrameTracker>>> {
        self.shm.get(&id).cloned()
    }
}

use core::cmp::min;
use core::num::NonZeroUsize;
use lru::LruCache;
use riscv::register::satp;
use crate::config::MAX_ASID;

pub type ASID = u16;

pub struct ASIDManager {
    cache: LruCache<usize, ASID>,
    allocated: usize,
}

impl ASIDManager {
    pub fn new() -> Option<Self> {
        let asid_cap = unsafe {
            let satp = satp::read();
            satp::set(satp.mode(), ASID::MAX as usize, satp.ppn());
            let cap = satp::read().asid();
            satp::set(satp.mode(), satp.asid(), satp.ppn());
            min(cap, MAX_ASID)
        };
        let asid_cap = NonZeroUsize::new(asid_cap)?;
        Some(Self {
            cache: LruCache::new(asid_cap),
            allocated: 0,
        })
    }

    pub fn get(&mut self, token: usize) -> Option<ASID> {
        self.cache.get(&token).copied()
    }

    pub fn assign(&mut self, token: usize) -> ASID {
        if self.allocated < self.cache.cap().get() {
            let asid = self.allocated as ASID;
            self.allocated += 1;
            self.cache.put(token, asid);
            asid
        } else {
            let recycled = self.cache.pop_lru().unwrap().1;
            self.cache.put(token, recycled);
            recycled
        }
    }
}

use core::arch::asm;
use core::cmp::min;
use core::ffi::CStr;
use core::mem::size_of;
use zerocopy::{AsBytes, FromBytes};
use crate::arch::{PAGE_SIZE, VirtAddr};
use crate::processor::hart::{KIntrGuard, local_hart};
use crate::result::{Errno, SyscallResult};

pub fn user_transmute_r<T: FromBytes>(addr: usize) -> SyscallResult<Option<&'static T>> {
    match addr {
        0 => Ok(None),
        _ => {
            let addr = VirtAddr(addr);
            check_slice_readable(addr, size_of::<T>())?;
            let bytes = unsafe { core::slice::from_raw_parts(addr.as_ptr(), size_of::<T>()) };
            Ok(Some(T::ref_from(bytes).unwrap()))
        }
    }
}

pub fn user_transmute_w<T: AsBytes + FromBytes>(addr: usize) -> SyscallResult<Option<&'static mut T>> {
    match addr {
        0 => Ok(None),
        _ => {
            let addr = VirtAddr(addr);
            check_slice_writable(addr, size_of::<T>())?;
            let bytes = unsafe { core::slice::from_raw_parts_mut(addr.as_ptr(), size_of::<T>()) };
            Ok(Some(T::mut_from(bytes).unwrap()))
        }
    }
}

pub fn user_transmute_str(addr: usize, max_len: usize) -> SyscallResult<Option<&'static str>> {
    match addr {
        0 => Ok(None),
        _ => {
            let mut cur_len = min(max_len, PAGE_SIZE - (addr % PAGE_SIZE));
            loop {
                let data = user_slice_r(addr, cur_len)?;
                if let Ok(cstr) = CStr::from_bytes_until_nul(data) {
                    return Ok(Some(cstr.to_str().map_err(|_| Errno::EINVAL)?));
                } else if cur_len == max_len {
                    return Err(Errno::ENAMETOOLONG);
                }
                cur_len = min(cur_len + PAGE_SIZE, max_len);
            }
        }
    }
}

pub fn user_slice_r(addr: usize, len: usize) -> SyscallResult<&'static [u8]> {
    if len == 0 {
        return Ok(&[]);
    }
    let addr = VirtAddr(addr);
    check_slice_readable(addr, len)?;
    let bytes = unsafe { core::slice::from_raw_parts(addr.as_ptr(), len) };
    Ok(bytes)
}

pub fn user_slice_w(addr: usize, len: usize) -> SyscallResult<&'static mut [u8]> {
    if len == 0 {
        return Ok(&mut []);
    }
    let addr = VirtAddr(addr);
    check_slice_writable(addr, len)?;
    let bytes = unsafe { core::slice::from_raw_parts_mut(addr.as_ptr(), len) };
    Ok(bytes)
}

fn check_slice_readable(addr: VirtAddr, len: usize) -> SyscallResult {
    if addr.0.checked_add(len).is_none() {
        return Err(Errno::EFAULT);
    }
    let _guard = KIntrGuard::new();
    local_hart().on_page_test = true;
    let start = addr.floor();
    let end = (addr + len).ceil();
    for vpn in start..end {
        if unsafe { try_read_u8(VirtAddr::from(vpn).as_ptr()) } {
            local_hart().on_page_test = false;
            return local_hart().last_page_fault;
        }
    }
    local_hart().on_page_test = false;
    Ok(())
}

fn check_slice_writable(addr: VirtAddr, len: usize) -> SyscallResult {
    if addr.0.checked_add(len).is_none() {
        return Err(Errno::EFAULT);
    }
    let _guard = KIntrGuard::new();
    local_hart().on_page_test = true;
    let start = addr.floor();
    let end = (addr + len).ceil();
    for vpn in start..end {
        if unsafe { try_write_u8(VirtAddr::from(vpn).as_ptr()) } {
            local_hart().on_page_test = false;
            return local_hart().last_page_fault;
        }
    }
    local_hart().on_page_test = false;
    Ok(())
}

#[naked]
unsafe extern "C" fn try_read_u8(addr: *const u8) -> bool {
    asm! {
    "mv t0, a0",
    "li a0, 1",
    "lb t0, 0(t0)",
    "li a0, 0",
    "ret",
    options(noreturn),
    }
}

#[naked]
unsafe extern "C" fn try_write_u8(addr: *mut u8) -> bool {
    asm! {
    "mv t0, a0",
    "li a0, 1",
    "lb t1, 0(t0)",
    "sb t1, 0(t0)",
    "li a0, 0",
    "ret",
    options(noreturn),
    }
}

