use alloc::vec::Vec;
use core::arch::global_asm;
use crate::sync::once::LateInit;

global_asm!(include_str!("release.asm"));

extern {
    fn builtin_apps();
    fn builtin_app_names();
}

#[inline]
fn builtin_app_num() -> usize {
    unsafe { *(builtin_apps as usize as *const usize) }
}

fn builtin_app_data(app_id: usize) -> &'static [u8] {
    let app_num_ptr = builtin_apps as usize as *const usize;
    let app_num = builtin_app_num();
    let app_start = unsafe {
        core::slice::from_raw_parts(app_num_ptr.add(1), app_num + 1)
    };
    assert!(app_id < app_num);
    unsafe {
        core::slice::from_raw_parts(
            app_start[app_id] as *const u8,
            app_start[app_id + 1] - app_start[app_id],
        )
    }
}

static APP_NAMES: LateInit<Vec<&'static str>> = LateInit::new();

pub fn init() {
    let app_num = builtin_app_num();
    let mut start = builtin_app_names as usize as *const u8;
    let mut apps = Vec::new();
    unsafe {
        for _ in 0..app_num {
            let mut end = start;
            while *end != b'\0' {
                end = end.add(1);
            }
            let slice = core::slice::from_raw_parts(start, end as usize - start as usize);
            let str = core::str::from_utf8(slice).unwrap();
            apps.push(str);
            start = end.add(1);
        }
        APP_NAMES.init(apps);
    }
}

pub fn builtin_app(name: &str) -> Option<&'static [u8]> {
    let app_num = builtin_app_num();
    (0..app_num)
        .find(|&i| APP_NAMES[i] == name)
        .map(builtin_app_data)
}

use alloc::collections::BTreeMap;
use core::future::Future;
use core::pin::Pin;
use core::task::{Context, Poll};
use core::time::Duration;
use pin_project::pin_project;
use crate::arch;
use crate::driver::BOARD_INFO;
use crate::sched::ffi::CLOCK_REALTIME;
use crate::sched::timer::sched_timer;
use crate::sync::mutex::IrqMutex;

const MICROS_PER_SEC: usize = 1000000;
const TICKS_PER_SEC: usize = 100;

pub trait DurationExt {
    fn as_ticks(&self) -> usize;
}

impl DurationExt for Duration {
    fn as_ticks(&self) -> usize {
        self.as_micros() as usize / (MICROS_PER_SEC / TICKS_PER_SEC)
    }
}

/// 获取从系统启动到现在的时间
pub fn cpu_time() -> Duration {
    if !BOARD_INFO.is_initialized() {
        return Duration::ZERO;
    }
    let ms = arch::hardware_ts() / (BOARD_INFO.freq / MICROS_PER_SEC);
    Duration::from_micros(ms as u64)
}

/// 获取实时时间
pub fn real_time() -> Duration {
    GLOBAL_CLOCK.get(CLOCK_REALTIME).unwrap() + cpu_time()
}

pub fn set_next_trigger() {
    let next_trigger = arch::hardware_ts() + BOARD_INFO.freq / TICKS_PER_SEC;
    arch::set_timer(next_trigger);
}

pub static GLOBAL_CLOCK: GlobalClock = GlobalClock::new();

pub struct GlobalClock(IrqMutex<BTreeMap<usize, Duration>>);

impl GlobalClock {
    const fn new() -> Self {
        Self(IrqMutex::new(BTreeMap::new()))
    }

    pub fn get(&self, clock_id: usize) -> Option<Duration> {
        let clock = self.0.lock();
        clock.get(&clock_id).copied()
    }

    pub fn set(&self, clock_id: usize, duration: Duration) {
        let mut clock = self.0.lock();
        clock.insert(clock_id, duration);
    }
}

#[pin_project]
pub struct TimeoutFuture<F: Future> {
    expire: Duration,
    sched: bool,
    #[pin]
    fut: F,
}

pub enum TimeoutResult<T> {
    Timeout,
    Ready(T),
}

impl<F: Future> TimeoutFuture<F> {
    pub fn new(wait: Duration, fut: F) -> Self {
        Self { expire: cpu_time() + wait, sched: false, fut }
    }
}

impl<F: Future> Future for TimeoutFuture<F> {
    type Output = TimeoutResult<F::Output>;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = self.project();
        match this.fut.poll(cx) {
            Poll::Ready(v) => Poll::Ready(TimeoutResult::Ready(v)),
            Poll::Pending => {
                if !*this.sched {
                    sched_timer(*this.expire, cx.waker().clone());
                    *this.sched = true;
                }
                if cpu_time() >= *this.expire {
                    Poll::Ready(TimeoutResult::Timeout)
                } else {
                    Poll::Pending
                }
            }
        }
    }
}

use alloc::collections::BinaryHeap;
use core::cmp::Reverse;
use core::future::Future;
use core::pin::Pin;
use core::task::{Context, Poll, Waker};
use core::time::Duration;
use lazy_static::lazy_static;
use pin_project::pin_project;
use crate::sched::time::cpu_time;
use crate::sync::mutex::IrqMutex;

struct Timer {
    expire: Duration,
    waker: Waker,
}

impl Timer {
    fn new(expire: Duration, waker: Waker) -> Self {
        Self { expire, waker }
    }
}

impl PartialEq for Timer {
    fn eq(&self, other: &Self) -> bool {
        self.expire == other.expire
    }
}

impl PartialOrd for Timer {
    fn partial_cmp(&self, other: &Self) -> Option<core::cmp::Ordering> {
        self.expire.partial_cmp(&other.expire)
    }
}

impl Eq for Timer {}

impl Ord for Timer {
    fn cmp(&self, other: &Self) -> core::cmp::Ordering {
        self.expire.cmp(&other.expire)
    }
}

struct TimerQueue(IrqMutex<BinaryHeap<Reverse<Timer>>>);

impl TimerQueue {
    fn push(&self, timer: Timer) {
        self.0.lock().push(Reverse(timer));
    }
}

lazy_static! {
    static ref TIMER_QUEUE: TimerQueue = TimerQueue(IrqMutex::new(BinaryHeap::new()));
}

pub fn sched_timer(expire: Duration, waker: Waker) {
    TIMER_QUEUE.push(Timer::new(expire, waker));
}

pub fn query_timer() -> bool {
    let now = cpu_time();
    let mut queue = TIMER_QUEUE.0.lock();
    if queue.is_empty() {
        return false;
    }
    while let Some(timer) = queue.peek() {
        if timer.0.expire <= now {
            let timer = queue.pop().unwrap();
            timer.0.waker.wake();
        } else {
            break;
        }
    }
    true
}

#[pin_project]
pub struct TimerFuture<F: Fn() -> Duration> {
    trigger: Duration,
    callback: F,
}

impl<F: Fn() -> Duration> TimerFuture<F> {
    pub fn new(trigger: Duration, callback: F) -> Self {
        Self { trigger, callback }
    }
}

impl<F: Fn() -> Duration> Future for TimerFuture<F> {
    type Output = ();

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        if cpu_time() >= self.trigger {
            self.trigger = (self.callback)();
            if self.trigger.is_zero() {
                return Poll::Ready(());
            }
        }
        sched_timer(self.trigger, cx.waker().clone());
        Poll::Pending
    }
}

use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use log::warn;
use crate::arch::VirtAddr;
use crate::driver::IrqDevice;
use crate::sync::mutex::IrqMutex;

pub struct PLIC {
    base_addr: VirtAddr,
    devices: IrqMutex<BTreeMap<usize, Weak<dyn IrqDevice>>>,
}

impl PLIC {
    pub(super) fn new(base_addr: VirtAddr) -> Self {
        Self { base_addr, devices: IrqMutex::default() }
    }

    pub(super) fn init(&self, harts: usize) {
        for context_id in 1..harts + 1 {
            self.set_threshold(context_id, 0);
            for intr_id in self.devices.lock().keys() {
                self.enable_intr(context_id, *intr_id);
                self.set_priority(*intr_id, 1);
            }
        }
    }

    pub(super) fn register_device(&self, intr_id: usize, device: Arc<dyn IrqDevice>) {
        self.devices.lock().insert(intr_id, Arc::downgrade(&device));
    }

    pub fn handle_irq(&self, hart_id: usize) {
        let context_id = hart_id + 1;
        let intr = self.claim(context_id);
        if intr != 0 {
            if let Some(device) = self.devices.lock().get(&intr) {
                match device.upgrade() {
                    Some(device) => device.handle_irq(),
                    None => warn!("[plic] Device {} is already dropped", intr),
                }
            }
            self.complete(context_id, intr);
        }
    }
}

#[allow(unused)]
impl PLIC {
    fn priority_ptr(&self, intr_id: usize) -> *mut u32 {
        (self.base_addr + intr_id * 4).as_ptr().cast()
    }

    fn pending_ptr(&self, intr_id: usize) -> *mut u32 {
        (self.base_addr + 0x1000 + 4 * (intr_id / 32)).as_ptr().cast()
    }

    fn intr_enable_ptr(&self, context_id: usize, intr_id: usize) -> *mut u32 {
        (self.base_addr + 0x2000 + 0x80 * context_id + 4 * (intr_id / 32)).as_ptr().cast()
    }

    fn threshold_ptr(&self, context_id: usize) -> *mut u32 {
        (self.base_addr + 0x200000 + 0x1000 * context_id).as_ptr().cast()
    }

    fn claim_complete_ptr(&self, context_id: usize) -> *mut u32 {
        (self.base_addr + 0x200000 + 0x1000 * context_id + 4).as_ptr().cast()
    }
}

#[allow(unused)]
impl PLIC {
    fn get_priority(&self, intr_id: usize) -> u32 {
        unsafe { self.priority_ptr(intr_id).read_volatile() & 7 }
    }

    fn set_priority(&self, intr_id: usize, priority: u32) {
        unsafe { self.priority_ptr(intr_id).write_volatile(priority & 7); }
    }

    fn is_pending(&self, intr_id: usize) -> bool {
        unsafe { ((self.pending_ptr(intr_id).read_volatile() >> (intr_id % 32)) & 1) == 1 }
    }

    fn is_intr_enabled(&self, context_id: usize, intr_id: usize) -> bool {
        unsafe { ((self.intr_enable_ptr(context_id, intr_id).read_volatile() >> (intr_id % 32)) & 1) == 1 }
    }

    fn enable_intr(&self, context_id: usize, intr_id: usize) {
        let ptr = self.intr_enable_ptr(context_id, intr_id);
        unsafe {
            let r = ptr.read_volatile();
            ptr.write_volatile(r | (1 << (intr_id % 32)));
        }
    }

    fn disable_intr(&self, context_id: usize, intr_id: usize) {
        let ptr = self.intr_enable_ptr(context_id, intr_id);
        unsafe {
            let r = ptr.read_volatile();
            ptr.write_volatile(r & !(1 << (intr_id % 32)));
        }
    }

    fn get_threshold(&self, context_id: usize) -> u32 {
        unsafe { self.threshold_ptr(context_id).read_volatile() & 7 }
    }

    fn set_threshold(&self, context_id: usize, threshold: u32) {
        unsafe { self.threshold_ptr(context_id).write_volatile(threshold & 7); }
    }

    fn claim(&self, context_id: usize) -> usize {
        unsafe { self.claim_complete_ptr(context_id).read_volatile() as usize }
    }

    fn complete(&self, context_id: usize, intr_id: usize) {
        unsafe { self.claim_complete_ptr(context_id).write_volatile(intr_id as u32); }
    }
}

use log::{debug, warn};
use crate::arch::{PAGE_SIZE, VirtAddr};
use crate::fs::fd::FdNum;
use crate::mm::addr_space::ASPerms;
use crate::mm::ffi::{IPC_PRIVATE, MapFlags, MapProt};
use crate::processor::current_process;
use crate::result::{Errno, SyscallResult};

pub fn sys_shmget(key: usize, len: usize, _flags: u32) -> SyscallResult<usize> {
    if len % PAGE_SIZE != 0 {
        return Err(Errno::EINVAL);
    }
    if key != IPC_PRIVATE {
        // TODO: Non-IPC_PRIVATE shmget
        warn!("[shmget] Non-IPC_PRIVATE is not supported");
        return Err(Errno::ENOSYS);
    }
    debug!("[shmget] key: {}, len: {}", key, len);
    current_process().inner.lock().addr_space.lock().shmget(len / PAGE_SIZE)
}

pub fn sys_shmctl(_shmid: i32, _op: i32, _buf: usize) -> SyscallResult<usize> {
    warn!("sys_shmctl: unimplemented");
    Ok(0)
}

pub fn sys_shmat(shmid: i32, addr: usize, _flags: u32) -> SyscallResult<usize> {
    if addr % PAGE_SIZE != 0 {
        return Err(Errno::EINVAL);
    }
    let start = match addr {
        0 => None,
        _ => Some(VirtAddr(addr).into()),
    };
    debug!("[shmat] shmid: {}, addr: {:?}", shmid, VirtAddr(addr));
    current_process().inner.lock().addr_space.lock().shmat(shmid as usize, start)
}

pub fn sys_brk(addr: usize) -> SyscallResult<usize> {
    let va = current_process().inner.lock().addr_space.lock().set_brk(VirtAddr(addr))?;
    debug!("[brk] {:#x} -> {:#x}", addr, va);
    Ok(va)
}

pub fn sys_munmap(addr: usize, len: usize) -> SyscallResult<usize> {
    if addr % PAGE_SIZE != 0 {
        return Err(Errno::EINVAL);
    }
    current_process().inner.lock().addr_space.lock()
        .munmap(VirtAddr(addr).into(), len.div_ceil(PAGE_SIZE))?;
    Ok(0)
}

pub fn sys_mmap(addr: usize, len: usize, prot: u32, flags: u32, fd: FdNum, offset: usize) -> SyscallResult<usize> {
    if addr % PAGE_SIZE != 0 || offset % PAGE_SIZE != 0 {
        return Err(Errno::EINVAL);
    }
    let prot = MapProt::from_bits_truncate(prot);
    let flags = MapFlags::from_bits_truncate(flags);
    let start = match addr {
        0 => None,
        _ => flags.contains(MapFlags::MAP_FIXED).then_some(VirtAddr(addr).into()),
    };
    debug!(
        "[mmap] start: {:?}, len: {:#x}, prot: {:?}, flags: {:?}, fd: {:?}, offset: {}",
        start, len, prot, flags, fd, offset,
    );
    let mut perms = ASPerms::from(prot);
    if flags.contains(MapFlags::MAP_SHARED) {
        perms |= ASPerms::S;
    } else if !flags.contains(MapFlags::MAP_PRIVATE) {
        return Err(Errno::EINVAL);
    }
    let proc_inner = current_process().inner.lock();
    if !flags.contains(MapFlags::MAP_ANONYMOUS) && fd != -1 {
        let fd_impl = proc_inner.fd_table.get(fd)?;
        let inode = fd_impl.file.metadata().inode.clone().ok_or(Errno::ENODEV)?;
        inode.metadata().page_cache.as_ref().ok_or(Errno::ENODEV)?;
        let name = inode.mnt_ns_path(&proc_inner.mnt_ns)?;
        proc_inner.addr_space.lock()
            .mmap(Some(name), start, len.div_ceil(PAGE_SIZE), perms, Some(inode), offset)
    } else {
        proc_inner.addr_space.lock()
            .mmap(None, start, len.div_ceil(PAGE_SIZE), perms, None, 0)
    }
}

pub fn sys_mprotect(addr: usize, len: usize, prot: u32) -> SyscallResult<usize> {
    if addr % PAGE_SIZE != 0 {
        return Err(Errno::EINVAL);
    }
    let prot = MapProt::from_bits_truncate(prot);
    debug!("[mprotect] addr: {:?}, len: {}, prot: {:?}",VirtAddr(addr), len, prot);
    current_process().inner.lock().addr_space.lock()
        .mprotect(VirtAddr(addr).into(), len.div_ceil(PAGE_SIZE), prot.into())?;
    Ok(0)
}

use core::mem::size_of;
use crate::fs::fd::{FdNum, FileDescriptor};
use crate::net::{copy_back_addr, make_unix_socket_pair, RecvFromFlags, SockAddr, Socket, TCP_MSS};
